import{_ as d,o as a,c as r,ag as e}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"音频传输协议","description":"","frontmatter":{"title":"音频传输协议"},"headers":[],"relativePath":"hardware/rk3588-mm/audio-protocol.md","filePath":"hardware/rk3588-mm/audio-protocol.md","lastUpdated":null}'),o={name:"hardware/rk3588-mm/audio-protocol.md"};function h(l,t,i,n,s,c){return a(),r("div",null,[...t[0]||(t[0]=[e('<p>上位机可通过网络与RK3588多模态盒子建立音频传输通道，可参照开发包中的<a href="https://www.yuque.com/iflyaiui/zzoolv/xk9rpv" title="Android示例代码" target="_blank" rel="noreferrer">Android示例代码</a>实现。</p><h2 id="音频传输协议" tabindex="-1">音频传输协议 <a class="header-anchor" href="#音频传输协议" aria-label="Permalink to &quot;音频传输协议&quot;">​</a></h2><h3 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h3><p>上位机可以通过建立tcp连接来获取到实时唇形降噪后的音频数据。</p><p><strong>设备IP</strong>：如果盒子为动态ip，可通过发送串口指令来获取ip，详见<a href="/hardware/rk3588-mm/semantic-protocol.html" title="发送串口">多模态麦克风和摄像头状态查询指令</a> 。 <strong>指定端口</strong>：9080</p><h3 id="消息格式" tabindex="-1">消息格式 <a class="header-anchor" href="#消息格式" aria-label="Permalink to &quot;消息格式&quot;">​</a></h3><p>消息格式与串口协议类似，唯一不同点为消息数据长度位从2个字节扩充到4个字节。</p><table tabindex="0"><thead><tr><th></th><th></th><th></th></tr></thead><tbody><tr><td><strong>字节</strong></td><td><strong>值</strong></td><td><strong>含义说明</strong></td></tr><tr><td>0</td><td>0xA5</td><td>同步头</td></tr><tr><td>1</td><td>0x01</td><td>用户ID</td></tr><tr><td>2</td><td>0xXX</td><td>消息类型</td></tr><tr><td>3~6</td><td>0xXXXXXXXX</td><td>消息数据长度</td></tr><tr><td>7~8</td><td>0xXXXX</td><td>消息ID</td></tr><tr><td>9~n</td><td>消息数据</td><td>消息数据</td></tr><tr><td>n+1</td><td>0xXX</td><td>内部校验码</td></tr></tbody></table><h3 id="通信规则" tabindex="-1">通信规则 <a class="header-anchor" href="#通信规则" aria-label="Permalink to &quot;通信规则&quot;">​</a></h3><ul><li>单工通信，盒子连续下发音频帧；</li><li>语音模组下发消息，上位机负责接收解析消息；</li><li>建立socket连接之后，盒子即开始下发音频帧；</li></ul><h3 id="通信格式" tabindex="-1">通信格式 <a class="header-anchor" href="#通信格式" aria-label="Permalink to &quot;通信格式&quot;">​</a></h3><p>通信格式定义了音频帧消息，详细如下：</p><table tabindex="0"><thead><tr><th></th><th></th><th></th><th></th><th></th><th></th><th></th><th></th><th></th><th></th><th></th><th></th><th></th><th></th><th></th><th></th><th></th><th></th><th></th><th></th><th></th></tr></thead><tbody><tr><td><strong>分类</strong></td><td><strong>同步头</strong></td><td><strong>用户ID</strong></td><td><strong>消息类型</strong></td><td><strong>消息长度</strong></td><td><strong>消息ID</strong></td><td><strong>消息数据</strong></td><td></td><td></td><td></td><td></td><td></td><td></td><td></td><td></td><td></td><td></td><td></td><td></td><td></td><td><strong>校验码</strong></td></tr><tr><td><strong>字节</strong></td><td>0</td><td>1</td><td>2</td><td>3~6</td><td>7~8</td><td>9</td><td></td><td>10</td><td></td><td>11~12</td><td></td><td>13~16</td><td></td><td></td><td></td><td>17~n</td><td></td><td></td><td></td><td>n+1</td></tr><tr><td><strong>音频帧</strong></td><td>0xA5</td><td>0x01</td><td>0x0a</td><td>同上</td><td>同上</td><td>VAD（端点检测）</td><td></td><td>通道号</td><td></td><td>0x00</td><td></td><td>帧号</td><td></td><td></td><td></td><td>音频</td><td></td><td></td><td></td><td>0x00</td></tr></tbody></table><h4 id="消息长度" tabindex="-1">消息长度： <a class="header-anchor" href="#消息长度" aria-label="Permalink to &quot;消息长度：&quot;">​</a></h4><p>数据格式中3-6字节为消息数据长度，消息长度编码为小端模式，即第3字节存储低字节，第6字节存储高字节。如确认消息中消息数据有4字节，则消息长度为4，编码到3-6字节就是0x04 0x00 0x00 0x00</p><h4 id="消息id" tabindex="-1">消息ID： <a class="header-anchor" href="#消息id" aria-label="Permalink to &quot;消息ID：&quot;">​</a></h4><p>数据格式中7-8字节为消息ID，与消息长度类似，也是小端模式编码。可以使用消息ID过滤因超时重发导致的重复消息。两字节长度的消息ID取值0-65535，所以在实际使用中需要循环使用，具体实现可以参考Android平台上的源码实现。</p><h4 id="校检码" tabindex="-1">校检码： <a class="header-anchor" href="#校检码" aria-label="Permalink to &quot;校检码：&quot;">​</a></h4><p>校验位固定为0x00</p><h3 id="音频帧消息" tabindex="-1">音频帧消息 <a class="header-anchor" href="#音频帧消息" aria-label="Permalink to &quot;音频帧消息&quot;">​</a></h3><p>消息数据中包含vad状态、音频帧编号、pcm音频</p><h4 id="vad状态" tabindex="-1">vad状态 <a class="header-anchor" href="#vad状态" aria-label="Permalink to &quot;vad状态&quot;">​</a></h4><ul><li>0 静音片段</li><li>1 开始说话</li><li>2 持续说话</li><li>3 结束说话</li></ul><h4 id="通道号-仅多人多模版本" tabindex="-1">通道号（仅多人多模版本） <a class="header-anchor" href="#通道号-仅多人多模版本" aria-label="Permalink to &quot;通道号（仅多人多模版本）&quot;">​</a></h4><p>标记当前音频对应哪一路说话人。</p><h4 id="音频帧号" tabindex="-1">音频帧号 <a class="header-anchor" href="#音频帧号" aria-label="Permalink to &quot;音频帧号&quot;">​</a></h4><p>编码为小端模式，即第13字节存储低字节，第16字节存储高字节。接收到的音频帧号应为连续递增的数字。</p><h4 id="音频数据" tabindex="-1">音频数据 <a class="header-anchor" href="#音频数据" aria-label="Permalink to &quot;音频数据&quot;">​</a></h4><p>音频数据格式为16k 16bit 单通道</p>',29)])])}const b=d(o,[["render",h]]);export{u as __pageData,b as default};
